from __future__ import annotations

from dataclasses import dataclass
from typing import Callable, Sequence

# ---------------------------------------------------------------------------
# Constants and specifications
# ---------------------------------------------------------------------------

WEEKDAY_NAMES: list[str] = [
    "Sunday", "Monday", "Tuesday", "Wednesday",
    "Thursday", "Friday", "Saturday",
]

MONTH_NAMES: list[str] = [
    "", "January", "February", "March", "April", "May", "June",
    "July", "August", "September", "October", "November", "December",
]

@dataclass(frozen=True)
class FieldSpec:
    """Definition of one cron field: its name and valid range."""
    name: str
    min_value: int
    max_value: int


FIELD_SPECS: list[FieldSpec] = [
    FieldSpec("minute", 0, 59),
    FieldSpec("hour", 0, 23),
    FieldSpec("day_of_month", 1, 31),
    FieldSpec("month", 1, 12),
    FieldSpec("day_of_week", 0, 6),
]


# ---------------------------------------------------------------------------
# Internal representation of a parsed field term
# ---------------------------------------------------------------------------

@dataclass(frozen=True)
class FieldSegment:
    """One comma-separated term within a field.

    start=None means "from the field's minimum".
    end=None means "to the field's maximum".
    step=None means "every value" (step of 1).
    """
    start: int | None
    end: int | None
    step: int | None


# ---------------------------------------------------------------------------
# Public structured results
# ---------------------------------------------------------------------------

@dataclass(frozen=True)
class CronField:
    """Structured representation of one parsed cron field."""
    expression: str
    allowed_values: frozenset[int]
    segments: tuple[FieldSegment, ...]

    @property
    def is_wildcard(self) -> bool:
        """True if the original expression was exactly '*'."""
        return self.expression.strip() == "*"

    @property
    def is_single_value(self) -> bool:
        """True if the field matches exactly one concrete value."""
        return len(self.allowed_values) == 1


@dataclass(frozen=True)
class CronSchedule:
    """Structured result of parsing a complete 5-field cron expression."""
    expression: str
    minute: CronField
    hour: CronField
    day_of_month: CronField
    month: CronField
    day_of_week: CronField

    def describe(self) -> str:
        """Return a human-readable English description of the schedule."""
        # Fast path for the most common "always" expression
        if self.expression.strip() == "* * * * *":
            return "Every minute"

        time_phrase = _describe_time(self.minute, self.hour)
        dom_phrase = _describe_day_of_month(self.day_of_month)
        dow_phrase = _describe_day_of_week(self.day_of_week)
        month_phrase = _describe_month(self.month)

        # Combine day-of-month and day-of-week phrases when both are present.
        # Cron treats them as "or", but we produce a readable approximation.
        day_phrases: list[str] = []
        if dom_phrase:
            day_phrases.append(dom_phrase)
        if dow_phrase:
            day_phrases.append(dow_phrase)

        if day_phrases:
            if len(day_phrases) == 1:
                day_clause = day_phrases[0]
            else:
                day_clause = f"{day_phrases[0]} and {day_phrases[1]}"
        else:
            day_clause = None

        # Special enhancement: "on the 1st of every month" style
        if (
            dom_phrase
            and self.day_of_month.is_single_value
            and self.month.is_wildcard
            and not dow_phrase
        ):
            # Replace "on the X" with "on the X of every month"
            base = dom_phrase  # e.g. "on the 1st"
            day_clause = f"{base} of every month"

        # Assemble final sentence
        parts: list[str] = []
        if time_phrase:
            parts.append(time_phrase)
        if day_clause:
            parts.append(day_clause)
        if month_phrase:
            parts.append(month_phrase)

        sentence = " ".join(parts).strip()
        if not sentence:
            return "Runs at every possible time"

        # Title-case the first letter to match example style
        return sentence[0].upper() + sentence[1:]


# ---------------------------------------------------------------------------
# Small, focused formatting helpers (used by description logic)
# ---------------------------------------------------------------------------

def _ordinal(n: int) -> str:
    """Return the ordinal English form of a positive integer (1 -> '1st')."""
    if 11 <= n % 100 <= 13:
        suffix = "th"
    else:
        suffix = {1: "st", 2: "nd", 3: "rd"}.get(n % 10, "th")
    return f"{n}{suffix}"


def _format_time(hour: int, minute: int) -> str:
    """Format hour and minute as HH:MM with leading zeros."""
    return f"{hour:02d}:{minute:02d}"


def _english_list(items: list[str]) -> str:
    """Join items into a grammatically natural English list."""
    if not items:
        return ""
    if len(items) == 1:
        return items[0]
    if len(items) == 2:
        return f"{items[0]} and {items[1]}"
    return ", ".join(items[:-1]) + f", and {items[-1]}"


def _describe_values(
    field: CronField,
    fmt: Callable[[int], str],
) -> str:
    """Describe the allowed values of a field using the supplied formatter.

    Produces "1 through 5", "Monday, Wednesday, and Friday", or a single value.
    """
    if field.is_wildcard:
        return "every"
    values = sorted(field.allowed_values)
    if len(values) == 1:
        return fmt(values[0])
    # Contiguous range?
    if values == list(range(values[0], values[-1] + 1)):
        return f"{fmt(values[0])} through {fmt(values[-1])}"
    # Discrete list
    return _english_list([fmt(v) for v in values])


