    """Produce the time-of-day portion of the description."""
    m_expr = minute.expression.strip()
    h_expr = hour.expression.strip()

    # "* *"
    if m_expr == "*" and h_expr == "*":
        return "every minute"

    # "*/N *"
    is_step_min, step = _is_step_on_any_base(minute)
    if is_step_min and h_expr == "*":
        if step == 1:
            return "every minute"
        return f"every {step} minutes"

    # "0 */N" -> "Every N hours, on the hour"
    if minute.allowed_values == {0}:
        is_step_hour, step = _is_step_on_any_base(hour)
        if is_step_hour:
            if step == 1:
                return "every hour, on the hour"
            return f"every {step} hours, on the hour"

    # Specific time: both fields have exactly one value
    if minute.is_single_value and hour.is_single_value:
        h = _get_single_value(hour)
        m = _get_single_value(minute)
        if h == 0 and m == 0:
