    """Parse a single cron field using the provided field specification.

    This function is the single shared implementation for parsing minutes,
    hours, day_of_month, month, and day_of_week.
    """
    expr = expression.strip()
    if not expr:
        raise ValueError(f"Empty {spec.name} field")

    segments: list[FieldSegment] = []
    allowed: set[int] = set()

    if expr == "*":
        seg = FieldSegment(start=None, end=None, step=None)
        segments.append(seg)
        allowed = set(range(spec.min_value, spec.max_value + 1))
    else:
        raw_parts = [p.strip() for p in expr.split(",") if p.strip()]
        if not raw_parts:
            raise ValueError(f"Invalid {spec.name} field: '{expression}'")

        for part in raw_parts:
            seg = _parse_segment(part, spec.min_value, spec.max_value, spec.name)
            segments.append(seg)
            part_values = _expand_segment(seg, spec.min_value, spec.max_value)
            _validate_allowed_values(part_values, spec.min_value, spec.max_value, spec.name)
            allowed.update(part_values)

    if not allowed:
        raise ValueError(f"Invalid {spec.name} field: '{expression}' produced no values")

    return CronField(
        expression=expr,
        allowed_values=frozenset(allowed),
        segments=tuple(segments),
    )


# ---------------------------------------------------------------------------
# Public entry point
# ---------------------------------------------------------------------------

def parse_cron(expression: str) -> CronSchedule:
    """Parse a standard 5-field cron expression into a CronSchedule.

    Raises ValueError with a clear message for any invalid input.
    """
    fields = _split_expression(expression)
    _validate_field_count(fields)

    parsed_fields: list[CronField] = []
    for raw_field, spec in zip(fields, FIELD_SPECS):
        parsed = parse_field(raw_field, spec)
        parsed_fields.append(parsed)

    return CronSchedule(
        expression=expression.strip(),
        minute=parsed_fields[0],
        hour=parsed_fields[1],
        day_of_month=parsed_fields[2],
        month=parsed_fields[3],
        day_of_week=parsed_fields[4],
    )


